import math
import random

def find_period(a, N):
    r = 1
    current = a % N
    while current != 1 and r < N:
        current = (current * a) % N
        r += 1
    return r if current == 1 else None

def shors_algorithm(N, max_attempts=10):
    """
    Shor's algorithm (classical simulation).
    """
    # Handle N even
    if N % 2 == 0:
        return (2, N // 2)

    # Handle perfect powers
    for k in range(2, int(math.log2(N)) + 1):
        a = round(N ** (1/k))
        if a ** k == N:
            return (a, a ** (k-1))

    # Main loop: try random a
    for _ in range(max_attempts):
        a = random.randint(2, N - 2)

        # Check if we're lucky (gcd > 1)
        g = math.gcd(a, N)
        if g > 1:
            return (g, N // g)

        # Find period
        r = find_period(a, N)
        if r is None or r % 2 != 0:
            continue

        # Try to extract factors
        x = pow(a, r // 2, N)
        if x == N - 1:
            continue

        p = math.gcd(x - 1, N)
        if 1 < p < N:
            return (p, N // p)

        q = math.gcd(x + 1, N)
        if 1 < q < N:
            return (q, N // q)

    return None

# Test on various semiprimes
for N in [15, 21, 35, 55, 77, 91]:
    result = shors_algorithm(N)
    if result:
        p, q = result
        verify = '✓' if p * q == N else '✗'
        print(f"{N} = {p} × {q} {verify}")
    else:
        print(f"{N}: factorization failed ✗")
